import os
import shutil

def get_ls_result(dir_path: str) -> str:
    try:
        if not os.path.isabs(dir_path) or not os.path.isdir(dir_path):
            return ""
        safe_base = "/safe/directory"
        abs_dir_path = os.path.abspath(dir_path)
        if not abs_dir_path.startswith(os.path.abspath(safe_base)):
            return ""
        try:
            files = os.listdir(dir_path)
            return "\n".join(files)
        except Exception:
            return ""
    except Exception:
        return ""
